import{_ as e,o as i,c as a,ag as t}from"./chunks/framework.CvgP6Fyv.js";const k=JSON.parse('{"title":"Prerequisites","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/prerequisites.md","filePath":"getting-started/prerequisites.md","lastUpdated":null}'),n={name:"getting-started/prerequisites.md"};function l(p,s,o,r,h,d){return i(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h1><p>Before creating your first experiment, make sure your environment meets the following requirements.</p><h2 id="node-version" tabindex="-1">Node version <a class="header-anchor" href="#node-version" aria-label="Permalink to &quot;Node version {#node-version}&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Node 20 is the minimum. Node 24 is recommended.</p><p>The generated project&#39;s <code>.nvmrc</code> is set to <code>24</code>. Running an older Node version will cause compatibility issues with pnpm 10.</p></div><p>Install and manage Node versions with <a href="https://github.com/nvm-sh/nvm" target="_blank" rel="noreferrer">nvm</a>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 24</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 24</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # v24.x.x</span></span></code></pre></div><p>Every generated project ships with a <code>.nvmrc</code> file. Running <code>nvm use</code> inside the project root will switch to the correct version automatically.</p><div class="tip custom-block"><p class="custom-block-title">Windows users</p><p>Use <a href="https://github.com/coreybutler/nvm-windows" target="_blank" rel="noreferrer">nvm-windows</a> instead of nvm.</p></div><div class="danger custom-block"><p class="custom-block-title">Node 16 is incompatible</p><p>The system default Node on some machines is 16. pnpm 10.30.1 requires Node 18 at minimum. Always run <code>nvm use 24</code> before any <code>pnpm</code> or <code>node</code> commands.</p></div><h2 id="pnpm" tabindex="-1">pnpm <a class="header-anchor" href="#pnpm" aria-label="Permalink to &quot;pnpm {#pnpm}&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Exact version required</p><p>The generated project&#39;s <code>packageManager</code> field is set to <code>pnpm@10.30.1</code>. Using a different version will produce lockfile format mismatches.</p></div><p><strong>Install via Corepack (recommended):</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prepare</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pnpm@10.30.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --activate</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 10.30.1</span></span></code></pre></div><p><strong>Install via npm (alternative):</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pnpm@10.30.1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 10.30.1</span></span></code></pre></div><p>Why exact? The pnpm lockfile format changes between minor versions. Projects checked in with a <code>pnpm-lock.yaml</code> from <code>10.30.1</code> will fail <code>--frozen-lockfile</code> installs on any other version.</p><h2 id="playwright" tabindex="-1">Playwright <a class="header-anchor" href="#playwright" aria-label="Permalink to &quot;Playwright {#playwright}&quot;">​</a></h2><p>Playwright is only needed if you enable E2E testing during scaffolding (the CLI prompts you).</p><p>If you answered <strong>Yes</strong> to E2E at scaffold time, the CLI installs browsers automatically after generating your project. You do not need to do anything extra.</p><p>To install browsers manually (e.g. after cloning an existing E2E-enabled project):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-experiment</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>This downloads Chromium, Firefox, and WebKit to <code>~/.cache/ms-playwright</code>. Plan for approximately 300 MB of disk space.</p><div class="tip custom-block"><p class="custom-block-title">Default browser</p><p>The generated <code>playwright.config.js</code> uses <code>Desktop Chrome</code> only. You do not need all three browsers for smoke testing.</p></div><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><p>Run these commands to confirm your environment is ready:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # v20.x.x or v24.x.x</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 10.30.1</span></span></code></pre></div><p>Once both pass, continue to <a href="/getting-started/installation.html">Installation</a>.</p>`,27)])])}const g=e(n,[["render",l]]);export{k as __pageData,g as default};
